import { ref } from 'vue'
import { useStore } from 'vuex'
import { auth } from '@/api/auth'
import { showToast } from '@/components/ToastMessage'

export function useNickname() {
  const store = useStore()

  // 状态
  const showNicknameModal = ref(false)
  const newNickname = ref('')
  const loading = ref(false)

  // 昵称验证函数
  const validateNickname = (nickname) => {
    if (!nickname) {
      showToast('请输入昵称', 'warning')
      return false
    }

    // 检查长度
    if (nickname.length < 4 || nickname.length > 8) {
      showToast('昵称长度需要在4-8位之间', 'warning')
      return false
    }

    // 只允许中文、字母、数字
    const nicknameRegex = /^[\u4e00-\u9fa5a-zA-Z0-9]+$/
    if (!nicknameRegex.test(nickname)) {
      showToast('昵称只能包含中文、字母、数字', 'warning')
      return false
    }

    return true
  }

  // 修改昵称处理函数
  const handleUpdateNickname = async () => {
    const nickname = newNickname.value.trim()

    if (!validateNickname(nickname)) return

    try {
      loading.value = true
      const response = await auth.updateUsername({ username: nickname })

      if (response.data?.code === 200) {
        // 更新 store 中的 userInfo
        store.commit('SET_USER_INFO', {
          ...store.state.userInfo,
          username: nickname
        })

        showToast('昵称修改成功', 'success')
        showNicknameModal.value = false
        newNickname.value = ''
      }
    } catch (error) {
      showToast(error.message || '昵称修改失败', 'error')
    } finally {
      loading.value = false
    }
  }

  // 打开昵称修改弹窗
  const openNicknameModal = () => {
    newNickname.value = store.state.userInfo?.username || ''
    showNicknameModal.value = true
  }

  // 关闭昵称修改弹窗
  const closeNicknameModal = () => {
    showNicknameModal.value = false
    newNickname.value = ''
  }

  return {
    showNicknameModal,
    newNickname,
    loading,
    handleUpdateNickname,
    openNicknameModal,
    closeNicknameModal
  }
}
